    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();

        PriorityQueue<int[]> youngTeam = new PriorityQueue<>((a, b) -> b[0] - a[0]); // Max-heap
        PriorityQueue<int[]> oldTeam = new PriorityQueue<>(Comparator.comparingInt(a -> a[0])); // Min-heap

        int youngRating = 0, oldRating = 0;

        for (int i = 0; i < N; i++) {
            int age = scanner.nextInt();
            int rating = scanner.nextInt();

            // Add chef to the correct team based on age
            if (youngTeam.isEmpty() || (!oldTeam.isEmpty() && age < oldTeam.peek()[0])) {
                youngTeam.offer(new int[]{age, rating});
                youngRating += rating;
            } else {
                oldTeam.offer(new int[]{age, rating});
                oldRating += rating;
            }

            // Balance the teams
            if (youngTeam.size() > oldTeam.size() + 1) {
                int[] oldestYoung = youngTeam.poll();
                youngRating -= oldestYoung[1];
                oldTeam.offer(oldestYoung);
                oldRating += oldestYoung[1];
            } else if (oldTeam.size() > youngTeam.size()) {
                int[] youngestOld = oldTeam.poll();
                oldRating -= youngestOld[1];
                youngTeam.offer(youngestOld);
                youngRating += youngestOld[1];
            }

            // Output the absolute difference between team ratings
