const readline = require('readline');

class MaxHeap {
    constructor() {
        this.heap = [];
    }

    insert(value) {
        this.heap.push(value);
        this.bubbleUp();
    }

    bubbleUp() {
        let index = this.heap.length - 1;
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[index][0] > this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else break;
        }
    }

    extractMax() {
        if (this.heap.length < 2) return this.heap.pop();
        const max = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown();
        return max;
    }

    bubbleDown() {
        let index = 0;
        const length = this.heap.length;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let largestIndex = index;

            if (leftChildIndex < length && this.heap[leftChildIndex][0] > this.heap[largestIndex][0]) {
                largestIndex = leftChildIndex;
            }
            if (rightChildIndex < length && this.heap[rightChildIndex][0] > this.heap[largestIndex][0]) {
                largestIndex = rightChildIndex;
            }
            if (largestIndex === index) break;
            [this.heap[index], this.heap[largestIndex]] = [this.heap[largestIndex], this.heap[index]];
            index = largestIndex;
        }
    }

    size() {
        return this.heap.length;
    }

    getMax() {
        return this.heap[0];
    }
}

class MinHeap {
    constructor() {
        this.heap = [];
    }

    insert(value) {
        this.heap.push(value);
        this.bubbleUp();
    }

    bubbleUp() {
        let index = this.heap.length - 1;
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else break;
        }
    }

    extractMin() {
        if (this.heap.length < 2) return this.heap.pop();
        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown();
        return min;
    }

    bubbleDown() {
        let index = 0;
        const length = this.heap.length;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallestIndex = index;

            if (leftChildIndex < length && this.heap[leftChildIndex][0] < this.heap[smallestIndex][0]) {
                smallestIndex = leftChildIndex;
            }
            if (rightChildIndex < length && this.heap[rightChildIndex][0] < this.heap[smallestIndex][0]) {
                smallestIndex = rightChildIndex;
            }
            if (smallestIndex === index) break;
            [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
            index = smallestIndex;
        }
    }

    size() {
        return this.heap.length;
    }

    getMin() {
        return this.heap[0];
    }
}

function manageTeams(chefs) {
    const youngTeam = new MaxHeap();
    const oldTeam = new MinHeap();
    let youngRating = 0, oldRating = 0;

    for (const [age, rating] of chefs) {
        // Add chef to the correct team based on age
        if (youngTeam.size() === 0 || (oldTeam.size() > 0 && age < oldTeam.getMin()[0])) {
            youngTeam.insert([age, rating]);
            youngRating += rating;
        } else {
            oldTeam.insert([age, rating]);
            oldRating += rating;
        }

        // Balance the teams
        if (youngTeam.size() > oldTeam.size() + 1) {
            const oldestYoung = youngTeam.extractMax();
            youngRating -= oldestYoung[1];
            oldTeam.insert(oldestYoung);
            oldRating += oldestYoung[1];
        } else if (oldTeam.size() > youngTeam.size()) {
            const youngestOld = oldTeam.extractMin();
            oldRating -= youngestOld[1];
            youngTeam.insert(youngestOld);
            youngRating += youngestOld[1];
        }

        // Calculate and output the absolute difference between team ratings
        console.log(Math.abs(youngRating - oldRating));
    }
}

