const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let chefs = [];
let numberOfChefs = 0;

rl.on('line', (line) => {
    // First line contains the number of chefs
    if (numberOfChefs === 0) {
        numberOfChefs = parseInt(line);
    } else {
        // Next lines contain age and rating of each chef
        const [age, rating] = line.split(' ').map(Number);
        chefs.push([age, rating]);

        // If we have read all chefs, manage teams
        if (chefs.length === numberOfChefs) {
            manageTeams(chefs);
            rl.close();
        }
